const peer    = String(inItem.phone_number || '').trim();
const key = account && peer ? `${account}:${peer}` : (peer || 'unknown');

const session = (store.sessions && store.sessions[key]) || { state: 'idle', ts: 0, updatedAt: 0 };

return [{
  json: {
    ...inItem,
    session_state: session.state,
    session_ts: session.updatedAt || session.ts || 0,
    used_key: key,
    session_name: session.name || inItem.contact_name || 'عميل'
  }
}];

