const items = $input.all();

// نعتبر أنه "وجد صف" فقط إذا:
const hasData =
  items.length > 0 &&
  items.some(it => it && it.json && Object.keys(it.json).length > 0); // مش فاضي

if (hasData) {
  // رجّع كل العناصر مع found=true، واحفظ الاقتران مع عناصر الإدخال
  return items.map((item, idx) => ({
    json: { ...item.json, found: true },
    pairedItem: { item: idx },   // مهم لتفادي التحذير والحفاظ على .item
  }));
}

// ما في نتائج من الشيت → رجّع عنصر واحد مع found=false (وبدون كسر الاقتران)
const base = items[0] || { json: {} };
return [{
  json: { ...base.json, found: false },
  pairedItem: base.pairedItem ?? { item: 0 },
}];

