const g = $getWorkflowStaticData('global');
const inItem = $input.first().json;

// 🏷️ PART 1: Label Tracker - تتبع التسميات
g.labels = g.labels || {};

const account = String(inItem.phone_number_id || '').trim();
const peer = String(inItem.phone_number || '').trim();
const interactiveReply = String(inItem.interactive_reply || '').trim();

if (account && peer) {
  const key = `${account}:${peer}`;
  let label = g.labels[key] || ''; // ✅ احتفظ بالـ label السابق إذا لم يتغير

  // القائمة الرئيسية
  if (interactiveReply === 'm_prices') {
    label = 'الأسعار';
  } else if (interactiveReply === 'm_new_request') {
    label = 'طلب جديد';
  } else if (interactiveReply === 'm_track_request') {
    label = 'متابعة طلب';
  } else if (interactiveReply === 'm_transfer') {
    label = 'نقل الخادمات';
  } else if (interactiveReply === 'm_translation') {
    label = 'الترجمة';
  } else if (interactiveReply === 'm_talk_to_agent') {
    label = 'التحدث مع موظف';
  }
  // الشكاوى والدعم
  else if (interactiveReply === 'complaint_worker') {
    label = 'مشكلة مع العاملة';
  } else if (interactiveReply === 'complaint_service') {
    label = 'مشكلة في الخدمة';
  } else if (interactiveReply === 'complaint_delay') {
    label = 'تأخير في الإجراءات';
  } else if (interactiveReply === 'complaint_financial') {
    label = 'مشاكل مالية';
  } else if (interactiveReply === 'complaint_other') {
    label = 'شكوى أخرى';
  }
  // الأقسام الفرعية
  else if (interactiveReply && interactiveReply.startsWith('price_')) {
    label = 'الأسعار';
  } else if (interactiveReply && interactiveReply.startsWith('req_')) {
    label = 'طلب جديد';
  }

  // ✅ حفظ التسمية (حتى لو كانت فارغة لنحتفظ بآخر label)
  g.labels[key] = label;
}

// 🤖 PART 2: Bot Enable Check - فحص تفعيل البوت
g.botEnabled = g.botEnabled || {};
if (g.botMasterOn === undefined) {
  g.botMasterOn = true;
}

let botEnabled = g.botMasterOn;

if (account && peer) {
  const exactKey = `${account}:${peer}`;
  const defaultKey = `default:${peer}`;

  if (g.botEnabled.hasOwnProperty(exactKey)) {
    botEnabled = g.botEnabled[exactKey] === true;
  }
  else if (g.botEnabled.hasOwnProperty(defaultKey)) {
    botEnabled = g.botEnabled[defaultKey] === true;
  }
}

return [{
  json: {
    ...inItem,
    bot_enabled: botEnabled
  }
}];

const g = $getWorkflowStaticData('global');
g.messages = g.messages || [];
g.contacts = g.contacts || {};

const inItem = $input.first().json;
const account = String(inItem.phone_number_id || '').trim();
const peer = String(inItem.phone_number || '').trim();
const key = account && peer ? `${account}:${peer}` : null;

if (!account || !peer) {
  return [{ json: inItem }];
}

let text = (inItem.message_text || '').trim();
let meta;
// ===== Helper functions =====
function inferExtFromMime(mime) {
  if (!mime) return null;
  const map = {
    'application/pdf': 'pdf',
    'application/msword': 'doc',
    'application/vnd.openxmlformats-officedocument.wordprocessingml.document': 'docx',
    'application/vnd.ms-excel': 'xls',
    'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet': 'xlsx',
    'application/vnd.ms-powerpoint': 'ppt',
    'application/vnd.openxmlformats-officedocument.presentationml.presentation': 'pptx',
    'text/plain': 'txt',
    'text/csv': 'csv',
    'application/zip': 'zip',
    'application/json': 'json'
  };
  return map[mime] || null;
}

function safeFilename(name) {
  // تنظيف الاسم من الرموز غير المسموح بها
  return String(name || '')
    .replace(/[\\/:*?"<>|]+/g, '_')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, 120);
}

function ensureExt(name, extFallback) {
  const hasExt = /\.[a-z0-9]{1,6}$/i.test(name || '');
  if (hasExt) return name;
  const ext = extFallback ? `.${extFallback}` : '';
  return `${name || 'document'}${ext}`;
}
// =============================

// ✅ وسائط - نحفظ media_id فقط (الملف في Data Table)
if (inItem.media_type && inItem.media_id) {
  const mediaType = inItem.media_type;

  if (mediaType === 'image') {
    text = '🖼️ صورة' + (inItem.media_caption ? ': ' + inItem.media_caption : '');
    meta = { 
      kind: 'media', 
      type: 'image',
      media_id: inItem.media_id,  // ✅ المفتاح فقط
      // ❌ بدون base64 - موجود في Data Table
      caption: inItem.media_caption
    };
  } 
  else if (mediaType === 'video') {
    text = '🎥 فيديو' + (inItem.media_caption ? ': ' + inItem.media_caption : '');
    meta = { 
      kind: 'media', 
      type: 'video',
      media_id: inItem.media_id,
      caption: inItem.media_caption
    };
  }
  else if (mediaType === 'audio') {
    text = '🎵 ملف صوتي';
    meta = { 
      kind: 'media', 
      type: 'audio',
      media_id: inItem.media_id
    };
  }
  else if (mediaType === 'voice') {
    text = '🎤 رسالة صوتية';
    meta = { 
      kind: 'media', 
      type: 'voice',
      media_id: inItem.media_id
    };
  }
else if (mediaType === 'document') {
  const mime = inItem.media_mime || inItem.media_mime_type; // إذا كانت متاحة من المصدر
  const extFromMime = inferExtFromMime(mime);
  const baseName = safeFilename(inItem.media_filename || 'مستند');
  const finalName = ensureExt(baseName, extFromMime || 'bin');

  text = '📄 ' + baseName;
  meta = { 
    kind: 'media', 
    type: 'document',
    media_id: inItem.media_id,
    caption: inItem.media_caption,
    filename: finalName,
    mime_type: mime || null
  };
}
}

// Interactive
if (inItem.interactive_reply && inItem.interactive_title) {
  meta = { 
    kind: 'interactive', 
    title: inItem.interactive_title,
    id: inItem.interactive_reply,
    type: inItem.interactive_type
  };
  text = inItem.interactive_title || text;
}

const msg = {
  account, peer,
  name: inItem.contact_name || peer,
  dir: 'in',
  text: text,
  ts: Math.floor(Date.now()/1000),
  business_phone: inItem.business_number || ''
};

if (meta) msg.meta = meta;

g.messages.push(msg);

// تنظيف القديم (الآن آمن - ما في ملفات ثقيلة)
if (g.messages.length > 5000) {
  g.messages.splice(0, g.messages.length - 5000);
}

// حفظ جهة الاتصال
if (!g.contacts[key]) {
  g.contacts[key] = {
    platform: 'whatsapp',
    account,
    peer,
    name: inItem.contact_name || peer
  };
} else {
  const gotName = inItem.contact_name;
  if (gotName && (!g.contacts[key].name || g.contacts[key].name === peer)) {
    g.contacts[key].name = gotName;
  }
}

return [{ json: inItem }];

// احفظ الحالة عند كل رسالة/كبسة زر
const inItem = $input.first().json;
const g = $getWorkflowStaticData('global');

// مفتاح الجلسة = الحساب:الرقم (أو الرقم إذا ما توفر الحساب)
const account = String(inItem.phone_number_id || '').trim();
const peer    = String(inItem.phone_number || '').trim();
const key = account && peer ? `${account}:${peer}` : (peer || 'unknown');

// الحالة التالية = id الزر إن وُجد، وإلا "typed_text" إن فيه نص
const nextState = inItem.interactive_reply
  ? String(inItem.interactive_reply)
  : (inItem.message_text ? 'typed_text' : 'unknown');

g.sessions = g.sessions || {};
g.sessions[key] = {
  state: nextState,
  name:  inItem.contact_name || 'عميل',
  phone: inItem.phone_number || '',
  account,
  updatedAt: Date.now()
};

return [{ json: { ...inItem, session_state: nextState, session_key: key } }];

const g = $getWorkflowStaticData('global');
g.messages = g.messages || [];
g.contacts = g.contacts || {};

const it = $input.first().json;
const account = String(it.phone_number_id || '').trim();
const peer = String(it.phone_number || '').trim();
const out = it._outgoing || {};

if (!account || !peer || !out.type) {
  return [{ json: { logged:false, reason:'missing account/peer/_outgoing', ...it } }];
}

const key = `${account}:${peer}`;
const name = it.contact_name || g.contacts[key]?.name || peer;
if (!g.contacts[key]) g.contacts[key] = { platform:'whatsapp', peer, account, name };
else g.contacts[key].name = name || g.contacts[key].name;

// 🔥 التعديل الرئيسي: استخراج النص الفعلي من payload
let displayText = '';

if (out.type === 'text' && out.payload?.text?.body) {
  // رسالة نصية عادية
  displayText = out.payload.text.body;

} else if (out.type === 'interactive' && out.payload?.interactive) {
  // رسالة قائمة تفاعلية
  const inter = out.payload.interactive;

  if (inter.body?.text) {
    displayText = inter.body.text;
  }

  // إضافة معلومات القائمة إذا كانت موجودة
  if (inter.action?.sections) {
    displayText += '\n\n📋 الخيارات المتاحة:';
    inter.action.sections.forEach(section => {
      if (section.rows) {
        section.rows.forEach(row => {
          displayText += `\n• ${row.title || row.id}`;
        });
      }
    });
  }

} else {
  // Fallback للـ preview إذا لم نستطع استخراج النص
  displayText = out.preview || '📤 تم إرسال رسالة';
}

const msg = {
  account, peer, name,
  dir: 'out',
  text: displayText,
  ts: Math.floor(Date.now()/1000),
  meta: { kind:'sent', type: out.type },
  business_phone: it.business_number || ''
};

g.messages.push(msg);
if (g.messages.length > 5000) g.messages.splice(0, g.messages.length - 5000);

return [{ json: { logged:true, ...it } }];

// حضّر الإرسال – القائمة الرئيسية
const j = $json;

const payload = {
  messaging_product: "whatsapp",
  to: j.phone_number,
  type: "interactive",
  interactive: {
    type: "list",
    body: {
      text: "مرحبًا بك 👋\nأنا البوت الذكي لمكتب فهد للاستقدام 🤖\nسأكون معك خطوة بخطوة لمساعدتك في أي استفسار ❤️‍🔥\n\n📌 يمكنك أيضًا زيارة موقعنا للاستفادة من العروض الحصرية:\n🌐 https://fahadrec.com\n\nاختر الخدمة التي تناسبك من القائمة التالية:"
    },
    footer: { text: "مكتب فهد للاستقدام" },
    action: {
      button: "القائمة الرئيسية",
      sections: [
        {
          title: "الخدمات المتاحة",
          rows: [
            { id: "m_prices",         title: "💲 الأسعار",           description: "الاطلاع على أسعار الاستقدام" },
            { id: "m_new_request",    title: "📝 تقديم طلب جديد",    description: "تقديم طلب استقدام جديد" },
            { id: "m_track_request",  title: "🔎 متابعة طلب سابق",   description: "متابعة حالة طلبك" },
            { id: "m_transfer",       title: "🔄 نقل الخادمات",      description: "طلب نقل خادمات" },
            { id: "m_translation",    title: "🌐 الترجمة الفورية",   description: "خدمة الترجمة الفورية" },
            { id: "m_complaints",     title: "🛠️ الشكاوى والدعم",    description: "تقديم شكوى أو طلب دعم" },
            { id: "m_about",          title: "🏢 عن المكتب",         description: "معلومات عن المكتب" },
            { id: "m_talk_to_agent",  title: "🤝 التحدث مع موظف",    description: "التواصل مع خدمة العملاء" }
          ]
        }
      ]
    }
  }
};

// نضيف وصف مختصر للداشبورد
return [{
  json: {
    ...j,
    _outgoing: {
      type: "interactive",
      preview: "📤 تم إرسال: القائمة الرئيسية (8 خيارات)",
      payload
    }
  }
}];

