g.messages = g.messages || [];
g.contacts = g.contacts || {};

const it = $input.first().json;
const account = String(it.phone_number_id || '').trim();
const peer = String(it.phone_number || '').trim();
const out = it._outgoing || {};

if (!account || !peer || !out.type) {
