// 💾 حفظ الملف في Data Table
const original = $('استخراج البيانات').first().json;
const binaryData = $input.first().binary?.data;

if (!binaryData || !binaryData.data) {
  console.error('❌ No binary data');
  return [{ json: original }];
}

const base64 = binaryData.data.toString('base64');
const mime = binaryData.mimeType || 'application/octet-stream';

console.log(`✅ Saving: ${original.media_type} - ${mime} - ${(base64.length * 0.75 / 1024).toFixed(2)} KB`);

return [{
  json: {
    // للـ Data Table
    media_id: original.media_id,
    account: original.phone_number_id,
    peer: original.phone_number,
    media_type: original.media_type,
    media_base64: base64,
    media_mime_type: mime,  // ✅ هذا مهم جداً
    caption: original.media_caption || '',
    filename: original.media_filename || '',
    created_at: Math.floor(Date.now() / 1000),

    // البيانات الأصلية
    phone_number_id: original.phone_number_id,
    phone_number: original.phone_number,
    business_number: original.business_number,
    message_text: original.message_text,
    interactive_reply: original.interactive_reply,
    interactive_title: original.interactive_title,
    interactive_type: original.interactive_type,
    contact_name: original.contact_name,
    is_status_update: original.is_status_update,
    media_downloaded: true,
    media_filename: original.media_filename,  // ✅ أضفها هنا

  }
}];

// 📥 تنزيل الوسائط من WhatsApp

const g = $getWorkflowStaticData('global');
const item = $input.first().json;

// إذا ما في media_id، تجاوز
if (!item.media_id) {
  return [{ json: item }];
}

try {
  // 1️⃣ جلب رابط الملف من WhatsApp API
  const mediaInfoUrl = `https://graph.facebook.com/v17.0/${item.media_id}`;
  const mediaInfoResponse = await fetch(mediaInfoUrl, {
    headers: {
      'Authorization': 'Bearer YOUR_TOKEN_HERE' // ⚠️ ضع التوكن هنا
    }
  });

  const mediaInfo = await mediaInfoResponse.json();
  const mediaUrl = mediaInfo.url;

  // 2️⃣ تنزيل الملف نفسه
  const mediaResponse = await fetch(mediaUrl, {
    headers: {
      'Authorization': 'Bearer YOUR_TOKEN_HERE' // ⚠️ ضع التوكن هنا
    }
  });

  const mediaBuffer = await mediaResponse.arrayBuffer();
  const mediaBase64 = Buffer.from(mediaBuffer).toString('base64');

  console.log(`✅ تم تنزيل الوسائط: ${item.media_type} - ${(mediaBase64.length * 0.75 / 1024).toFixed(2)} KB`);

  // 3️⃣ حفظ الملف مع البيانات
  return [{
    json: {
      ...item,
      media_url: mediaUrl,
      media_base64: mediaBase64, // الملف كـ base64
      media_mime_type: mediaInfo.mime_type
    }
  }];

} catch (error) {
  console.error('❌ خطأ في تنزيل الوسائط:', error);
  return [{ json: item }]; // أرجع البيانات الأصلية
}

// استرجاع البيانات الأصلية بعد Data Table
const original = $('حفظ الميديا').first().json;

return [{
