  }
}];

// 🕐 إضافة نظام Cooldown للقائمة الرئيسية (5 دقائق)
const g = $getWorkflowStaticData('global');
const inItem = $input.first().json;

// تهيئة التخزين
g.lastMenuSent = g.lastMenuSent || {};

const account = String(inItem.phone_number_id || '').trim();
const peer = String(inItem.phone_number || '').trim();
const key = `${account}:${peer}`;

// الوقت الحالي
const now = Date.now();

// آخر وقت تم إرسال القائمة فيه لهذا المستخدم
const lastSent = g.lastMenuSent[key] || 0;

// الفرق بالدقائق
const minutesPassed = (now - lastSent) / (1000 * 60);

// ✅ إذا مر أكثر من 5 دقائق، أرسل القائمة
if (minutesPassed >= 5) {
  console.log(`✅ Sending menu to ${key} (${minutesPassed.toFixed(1)} minutes since last)`);

  // تحديث وقت الإرسال
  g.lastMenuSent[key] = now;

  // السماح بإرسال القائمة
  return [{ 
    json: { 
      ...inItem,
      send_menu: true,
      cooldown_passed: true
    } 
  }];
}

// ❌ إذا لم يمر 5 دقائق بعد
const remainingMinutes = (5 - minutesPassed).toFixed(1);
console.log(`⏳ Menu cooldown active for ${key}. ${remainingMinutes} minutes remaining.`);

return [{ 
  json: { 
    ...inItem,
    send_menu: false,
    cooldown_active: true,
    remaining_minutes: remainingMinutes
  } 
}];
